async function transform(input, context) {
  // Récupérer les infos de l'image depuis les steps précédents
  const info = context.steps['extract-metadata']?.produces || [];

  // Calculer les tailles des miniatures
  const thumbnails = {
    small: { width: 150, height: 150, url: `${context.executionId}/thumb_small.jpg` },
    medium: { width: 400, height: 400, url: `${context.executionId}/thumb_medium.jpg` },
    large: { width: 800, height: 800, url: `${context.executionId}/thumb_large.jpg` }
  };

  // Générer le rapport
  const report = {
    processedAt: new Date().toISOString(),
    executionId: context.executionId,
    workflowName: context.workflowName,
    originalImage: input.files?.[0]?.originalName || 'unknown',
    thumbnails,
    status: 'completed',
    message: `Image analysée avec succès. 3 miniatures générées.`
  };

  return report;
}
